// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
long long dp[10000001];
int main() {
    int N, K, A, B, Q;
    scanf("%d %d %d %d", &N, &K, &A, &B);
    dp[1] = K;
    for (int i = 2; i <= N; i++) {
        dp[i] = (A * dp[i-1] + B * dp[i-1] * dp[i-1]) % MOD;
        for (int j = 1; j < i-1; j++) {
            dp[i] = (dp[i] + B * dp[j] * dp[i-j]) % MOD;
        }
    }
    scanf("%d", &Q);
    while (Q--) {
        int L, R;
        scanf("%d %d", &L, &R);
        long long sum = 0;
        for (int i = L; i <= R; i++) {
            sum = (sum + dp[i] * dp[i]) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

