            dp[i] = (A * dp[i-1] + B * dp[i-1] * dp[i-1]) % MOD;
            for (int j = 1; j < i-1; j++) {
                dp[i] = (dp[i] + B * dp[j] * dp[i-j]) % MOD;
            }
        }
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
